export function extractCustomerId(data) {
  return (
    data?.cid ||
    data?.customerId ||
    data?._id ||
    data?.id ||
    data?.user?.cid ||
    data?.user?.customerId ||
    data?.user?._id ||
    data?.user?.id ||
    data?.data?.cid ||
    data?.data?.customerId ||
    data?.data?._id ||
    data?.data?.id ||
    data?.data?.user?.cid ||
    data?.data?.user?.customerId ||
    data?.data?.user?._id ||
    data?.data?.user?.id ||
    null
  );
}

export function saveLoginSession(data, { checkout = false } = {}) {
  if (typeof window === "undefined") return null;

  const cid = extractCustomerId(data);

  localStorage.setItem("user", JSON.stringify(data));
  if (checkout) localStorage.setItem("checkoutUser", JSON.stringify(data));
  if (data?.token) localStorage.setItem("userToken", data.token);
  if (cid) localStorage.setItem("cid", cid);

  return cid;
}

export function getLoggedInCid() {
  if (typeof window === "undefined") return null;

  const savedCid = localStorage.getItem("cid");
  if (savedCid) return savedCid;

  try {
    const user = JSON.parse(localStorage.getItem("user") || "null");
    const cid = extractCustomerId(user);
    if (cid) localStorage.setItem("cid", cid);
    return cid;
  } catch {
    return null;
  }
}
